INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('982|Открытие Гренландии', 982, 'Открытие Гренландии', 1, 'Гренландия', 64.1814, -51.6941, 'Эрик Рыжий достиг Гренландии и основал там скандинавские поселения. Э́рик Ры́жий (950—1003), также известный как: Эйрик Рауда, Эйрик Рыжий, Эйрик Торвальдсон — скандинавский мореплаватель и первооткрыватель, основавший первое поселение в Гренландии.', 'https://ru.wikipedia.org/wiki/%D0%AD%D1%80%D0%B8%D0%BA_%D0%A0%D1%8B%D0%B6%D0%B8%D0%B9');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1000|Плавание к Винланду', 1000, 'Плавание к Винланду', 2, 'Северная Америка', 51.5953, -55.5333, 'Лейф Эрикссон считается одним из первых европейцев, достигших берегов Северной Америки. Лейф Э́рикссон Счастли́вый — древнескандинавский исследователь из Исландии.', 'https://ru.wikipedia.org/wiki/%D0%9B%D0%B5%D0%B9%D1%84');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1271|Путешествие Марко Поло в Азию', 1271, 'Путешествие Марко Поло в Азию', 3, 'Китай', 39.9042, 116.4074, 'Марко Поло совершил путешествие в Азию, описания которого значительно расширили европейские представления о Востоке. Ма́рко По́ло — венецианский купец и путешественник, представивший историю своего путешествия по Азии в «Книге о разнообразии мира».', 'https://ru.wikipedia.org/wiki/%D0%9F%D0%BE%D0%BB%D0%BE%2C_%D0%9C%D0%B0%D1%80%D0%BA%D0%BE');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1415|Начало португальских морских экспедиций', 1415, 'Начало португальских морских экспедиций', 4, 'Западная Африка', 32.6669, -16.9241, 'Португальские экспедиции вдоль побережья Африки стали началом активной эпохи морских географических открытий. Ге́нрих Морепла́ватель — инфант Португалии, сын короля Жуана I, организатор многих португальских морских экспедиций на юг от Мавритании вдоль западноафриканского побережья.', 'https://ru.wikipedia.org/wiki/%D0%93%D0%B5%D0%BD%D1%80%D0%B8%D1%85_%D0%9C%D0%BE%D1%80%D0%B5%D0%BF%D0%BB%D0%B0%D0%B2%D0%B0%D1%82%D0%B5%D0%BB%D1%8C');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1488|Открытие мыса Доброй Надежды', 1488, 'Открытие мыса Доброй Надежды', 5, 'Юг Африки', -34.3568, 18.474, 'Бартоломеу Диаш обогнул южную оконечность Африки, открыв путь из Атлантического океана в Индийский. Бартоломе́у Ди́аш де Нова́иш — португальский мореплаватель.', 'https://ru.wikipedia.org/wiki/%D0%94%D0%B8%D0%B0%D1%88%2C_%D0%91%D0%B0%D1%80%D1%82%D0%BE%D0%BB%D0%BE%D0%BC%D0%B5%D1%83');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1492|Открытие Америки', 1492, 'Открытие Америки', 6, 'Карибские острова', 24.5, -75, 'Экспедиция Христофора Колумба достигла островов Карибского моря. Это событие стало одним из ключевых моментов эпохи Великих географических открытий.', 'https://ru.wikipedia.org/wiki/%D0%9A%D0%BE%D0%BB%D1%83%D0%BC%D0%B1%2C_%D0%A5%D1%80%D0%B8%D1%81%D1%82%D0%BE%D1%84%D0%BE%D1%80');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1497|Достижение берегов Северной Америки', 1497, 'Достижение берегов Северной Америки', 7, 'Ньюфаундленд', 48.5417, -56.125, 'Джон Кабот достиг берегов Северной Америки, что стало важным этапом английских географических исследований. Джон Ка́бот — итальянский и французский мореплаватель и купец на английской службе, впервые исследовавший побережье Канады.', 'https://ru.wikipedia.org/wiki/%D0%9A%D0%B0%D0%B1%D0%BE%D1%82%2C_%D0%94%D0%B6%D0%BE%D0%BD');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1498|Морской путь в Индию', 1498, 'Морской путь в Индию', 8, 'Каликут, Индия', 11.25, 75.7667, 'Васко да Гама достиг Индии морским путём вокруг Африки. Это открытие усилило торговые связи Европы с Азией. Ва́ско да Га́ма — португальский мореплаватель эпохи Великих географических открытий.', 'https://ru.wikipedia.org/wiki/%D0%92%D0%B0%D1%81%D0%BA%D0%BE_%D0%B4%D0%B0_%D0%93%D0%B0%D0%BC%D0%B0');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1499|Исследование побережья Южной Америки', 1499, 'Исследование побережья Южной Америки', 9, 'Побережье Южной Америки', -5, -35, 'Америго Веспуччи исследовал побережье Южной Америки. Его описания сыграли большую роль в понимании того, что открытые земли являются отдельным континентом.', 'https://ru.wikipedia.org/wiki/%D0%92%D0%B5%D1%81%D0%BF%D1%83%D1%87%D1%87%D0%B8%2C_%D0%90%D0%BC%D0%B5%D1%80%D0%B8%D0%B3%D0%BE');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1500|Открытие Бразилии', 1500, 'Открытие Бразилии', 10, 'Бразилия', -16, -39, 'Педру Алвариш Кабрал достиг берегов Бразилии во время плавания к Индии. Пе́дру А́лвариш (А́лварес) Кабра́л (порт. Pedro Álvares Cabral — португальский дворянин, военачальник, капитан и исследователь.', 'https://ru.wikipedia.org/wiki/%D0%9A%D0%B0%D0%B1%D1%80%D0%B0%D0%BB%2C_%D0%9F%D0%B5%D0%B4%D1%80%D1%83');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1513|Открытие Тихого океана', 1513, 'Открытие Тихого океана', 11, 'Панамский перешеек', 9, -79, 'Бальбоа пересёк Панамский перешеек и стал одним из первых европейцев, увидевших воды Тихого океана с американского континента.', 'https://ru.wikipedia.org/wiki/%D0%9D%D1%83%D0%BD%D1%8C%D0%B5%D1%81_%D0%B4%D0%B5_%D0%91%D0%B0%D0%BB%D1%8C%D0%B1%D0%BE%D0%B0%2C_%D0%92%D0%B0%D1%81%D0%BA%D0%BE');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1519|Начало кругосветной экспедиции', 1519, 'Начало кругосветной экспедиции', 12, 'Испания', 40.2, -3.5, 'Экспедиция Фернана Магеллана стала первым путешествием, доказавшим возможность кругосветного плавания. Ферна́н Магелла́н — португальский и испанский мореплаватель с титулом аделантадо.', 'https://ru.wikipedia.org/wiki/%D0%9C%D0%B0%D0%B3%D0%B5%D0%BB%D0%BB%D0%B0%D0%BD%2C_%D0%A4%D0%B5%D1%80%D0%BD%D0%B0%D0%BD');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1520|Открытие Магелланова пролива', 1520, 'Открытие Магелланова пролива', 12, 'Юг Южной Америки', -52.637, -70.918, 'Магеллан обнаружил пролив, соединяющий Атлантический и Тихий океаны. Позднее этот пролив получил его имя. Ферна́н Магелла́н — португальский и испанский мореплаватель с титулом аделантадо.', 'https://ru.wikipedia.org/wiki/%D0%9C%D0%B0%D0%B3%D0%B5%D0%BB%D0%BB%D0%B0%D0%BD%2C_%D0%A4%D0%B5%D1%80%D0%BD%D0%B0%D0%BD');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1521|Достижение Филиппин', 1521, 'Достижение Филиппин', 12, 'Филиппины', 12.8, 122.05, 'Экспедиция Магеллана достигла Филиппин во время первого кругосветного плавания. Ферна́н Магелла́н — португальский и испанский мореплаватель с титулом аделантадо.', 'https://ru.wikipedia.org/wiki/%D0%9C%D0%B0%D0%B3%D0%B5%D0%BB%D0%BB%D0%B0%D0%BD%2C_%D0%A4%D0%B5%D1%80%D0%BD%D0%B0%D0%BD');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1524|Исследование восточного побережья Северной Америки', 1524, 'Исследование восточного побережья Северной Америки', 13, 'Восточное побережье Северной Америки', 40.7128, -74.006, 'Верраццано исследовал часть восточного побережья Северной Америки, включая район современного Нью-Йорка. Джова́нни да Веррацца́но — итальянский мореплаватель на французской службе, который первым из европейцев проплыл вдоль восточного побережья Северной Америки вплоть до Нью-Йоркской бухты и залива Наррагансетт.', 'https://ru.wikipedia.org/wiki/%D0%92%D0%B5%D1%80%D1%80%D0%B0%D1%86%D1%86%D0%B0%D0%BD%D0%BE%2C_%D0%94%D0%B6%D0%BE%D0%B2%D0%B0%D0%BD%D0%BD%D0%B8_%D0%B4%D0%B0');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1534|Исследование реки Святого Лаврентия', 1534, 'Исследование реки Святого Лаврентия', 14, 'Канада', 46.8139, -71.208, 'Жак Картье исследовал район реки Святого Лаврентия, что стало важным этапом французских исследований Северной Америки. Жак Картье́ — бретонский мореплаватель, положивший начало французской колонизации Северной Америки.', 'https://ru.wikipedia.org/wiki/%D0%9A%D0%B0%D1%80%D1%82%D1%8C%D0%B5%2C_%D0%96%D0%B0%D0%BA');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1542|Исследование Калифорнии', 1542, 'Исследование Калифорнии', 15, 'Калифорния', 37, -120, 'Хуан Родригес Кабрильо исследовал побережье Калифорнии, расширив знания европейцев о западном побережье Северной Америки.', 'https://ru.wikipedia.org/wiki/%D0%A0%D0%BE%D0%B4%D1%80%D0%B8%D0%B3%D0%B5%D1%81_%D0%9A%D0%B0%D0%B1%D1%80%D0%B8%D0%BB%D1%8C%D0%BE%2C_%D0%A5%D1%83%D0%B0%D0%BD');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1577|Кругосветное плавание Фрэнсиса Дрейка', 1577, 'Кругосветное плавание Фрэнсиса Дрейка', 16, 'Тихий океан', -13, -76, 'Фрэнсис Дрейк совершил одно из первых кругосветных плаваний после экспедиции Магеллана. Фрэнсис Дрейк — английский капитан, капер, военно-морской офицер и исследователь.', 'https://ru.wikipedia.org/wiki/%D0%94%D1%80%D0%B5%D0%B9%D0%BA%2C_%D0%A4%D1%80%D1%8D%D0%BD%D1%81%D0%B8%D1%81');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1594|Поиски Северо-Восточного прохода', 1594, 'Поиски Северо-Восточного прохода', 17, 'Арктика', 76, 60, 'Виллем Баренц исследовал арктические моря в поисках северного пути в Азию. Ви́ллем Ба́ренц — голландский мореплаватель и исследователь.', 'https://ru.wikipedia.org/wiki/%D0%92%D0%B8%D0%BB%D0%BB%D0%B5%D0%BC_%D0%91%D0%B0%D1%80%D0%B5%D0%BD%D1%86');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1606|Первые европейские исследования Австралии', 1606, 'Первые европейские исследования Австралии', 18, 'Север Австралии', -12.5, 141.5, 'Виллем Янсзон считается одним из первых европейцев, достигших берегов Австралии. Ви́ллем Я́нсзон — голландский мореплаватель и колониальный чиновник.', 'https://ru.wikipedia.org/wiki/%D0%AF%D0%BD%D1%81%D0%B7%D0%BE%D0%BD%2C_%D0%92%D0%B8%D0%BB%D0%BB%D0%B5%D0%BC');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1609|Исследование реки Гудзон', 1609, 'Исследование реки Гудзон', 19, 'Нью-Йорк', 40.7283, -73.9942, 'Генри Гудзон исследовал реку, которая позже получила его имя. Ге́нри Гудзо́н (Ха́дсон) — английский мореплаватель начала XVII века.', 'https://ru.wikipedia.org/wiki/%D0%93%D1%83%D0%B4%D0%B7%D0%BE%D0%BD%2C_%D0%93%D0%B5%D0%BD%D1%80%D0%B8');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1610|Исследование Гудзонова залива', 1610, 'Исследование Гудзонова залива', 19, 'Гудзонов залив', 60, -85, 'Генри Гудзон исследовал северные воды Америки, включая район Гудзонова залива. Ге́нри Гудзо́н (Ха́дсон) — английский мореплаватель начала XVII века.', 'https://ru.wikipedia.org/wiki/%D0%93%D1%83%D0%B4%D0%B7%D0%BE%D0%BD%2C_%D0%93%D0%B5%D0%BD%D1%80%D0%B8');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1616|Открытие мыса Горн', 1616, 'Открытие мыса Горн', 20, 'Мыс Горн', -55.98, -67.2892, 'Виллем Схаутен и Якоб Лемер открыли морской путь вокруг южной оконечности Южной Америки. Ви́ллем Корне́лис Сха́утен — голландский мореплаватель.', 'https://ru.wikipedia.org/wiki/%D0%A1%D1%85%D0%B0%D1%83%D1%82%D0%B5%D0%BD%2C_%D0%92%D0%B8%D0%BB%D0%BB%D0%B5%D0%BC_%D0%9A%D0%BE%D1%80%D0%BD%D0%B5%D0%BB%D0%B8%D1%81');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1642|Открытие Тасмании', 1642, 'Открытие Тасмании', 21, 'Тасмания', -42, 147, 'Абел Тасман достиг острова, который позже получил название Тасмания. А́бел(ь) Янсзон Та́сман — голландский мореплаватель, исследователь и купец.', 'https://ru.wikipedia.org/wiki/%D0%A2%D0%B0%D1%81%D0%BC%D0%B0%D0%BD%2C_%D0%90%D0%B1%D0%B5%D0%BB%D1%8C_%D0%AF%D0%BD%D1%81%D0%B7%D0%BE%D0%BD');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1642|Исследование Новой Зеландии', 1642, 'Исследование Новой Зеландии', 21, 'Новая Зеландия', -41.5833, 173.05, 'Экспедиция Абела Тасмана стала одной из первых европейских экспедиций, достигших берегов Новой Зеландии. А́бел(ь) Янсзон Та́сман — голландский мореплаватель, исследователь и купец.', 'https://ru.wikipedia.org/wiki/%D0%A2%D0%B0%D1%81%D0%BC%D0%B0%D0%BD%2C_%D0%90%D0%B1%D0%B5%D0%BB%D1%8C_%D0%AF%D0%BD%D1%81%D0%B7%D0%BE%D0%BD');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1648|Проход между Азией и Америкой', 1648, 'Проход между Азией и Америкой', 22, 'Берингов пролив', 65.9725, -168.7917, 'Семён Дежнёв прошёл морским путём между Азией и Северной Америкой, доказав наличие пролива между материками. Семён Ива́нович Дежнёв — русский путешественник, землепроходец, мореход, исследователь Северной и Восточной Сибири и Северной Америки, якутский атаман, торговец пушниной.', 'https://ru.wikipedia.org/wiki/%D0%94%D0%B5%D0%B6%D0%BD%D1%91%D0%B2%2C_%D0%A1%D0%B5%D0%BC%D1%91%D0%BD_%D0%98%D0%B2%D0%B0%D0%BD%D0%BE%D0%B2%D0%B8%D1%87');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1728|Исследование Берингова пролива', 1728, 'Исследование Берингова пролива', 23, 'Берингов пролив', 65.9725, -168.7917, 'Витус Беринг исследовал пролив между Азией и Северной Америкой в ходе Камчатской экспедиции. Ви́тус Ионассен Бе́ринг, также Ива́н Ива́нович Бе́ринг — русский мореплаватель датского происхождения, офицер российского флота, капитан-командор.', 'https://ru.wikipedia.org/wiki/%D0%91%D0%B5%D1%80%D0%B8%D0%BD%D0%B3%2C_%D0%92%D0%B8%D1%82%D1%83%D1%81_%D0%98%D0%BE%D0%BD%D0%B0%D1%81%D1%81%D0%B5%D0%BD');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1741|Открытие побережья Аляски', 1741, 'Открытие побережья Аляски', 23, 'Аляска', 58.3019, -134.4197, 'Экспедиция Витуса Беринга достигла берегов Аляски, что стало важным событием в исследовании северной части Тихого океана.', 'https://ru.wikipedia.org/wiki/%D0%91%D0%B5%D1%80%D0%B8%D0%BD%D0%B3%2C_%D0%92%D0%B8%D1%82%D1%83%D1%81_%D0%98%D0%BE%D0%BD%D0%B0%D1%81%D1%81%D0%B5%D0%BD');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1741|Исследование северо-западного побережья Америки', 1741, 'Исследование северо-западного побережья Америки', 24, 'Северо-запад Северной Америки', 55.3422, -131.6461, 'Алексей Чириков исследовал районы северо-западного побережья Северной Америки. Алексе́й Ильи́ч Чи́риков — русский дворянин, мореплаватель, капитан-командор (1747), исследователь северо-западного побережья Северной Америки, северной части Тихого океана и северо-восточного побережья Азии.', 'https://ru.wikipedia.org/wiki/%D0%A7%D0%B8%D1%80%D0%B8%D0%BA%D0%BE%D0%B2%2C_%D0%90%D0%BB%D0%B5%D0%BA%D1%81%D0%B5%D0%B9_%D0%98%D0%BB%D1%8C%D0%B8%D1%87');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1768|Первая экспедиция Джеймса Кука', 1768, 'Первая экспедиция Джеймса Кука', 25, 'Таити', -17.6667, -149.4667, 'Первая экспедиция Джеймса Кука была связана с научными наблюдениями и исследованием островов Тихого океана. Джеймс Кук — британский военный моряк, путешественник-исследователь, картограф и первооткрыватель, член Королевского общества (1776) и капитан Королевских ВМС.', 'https://ru.wikipedia.org/wiki/%D0%9A%D1%83%D0%BA%2C_%D0%94%D0%B6%D0%B5%D0%B9%D0%BC%D1%81');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1770|Исследование восточного побережья Австралии', 1770, 'Исследование восточного побережья Австралии', 25, 'Австралия', -33.8688, 151.2093, 'Джеймс Кук исследовал восточное побережье Австралии и нанёс его на карту. Джеймс Кук — британский военный моряк, путешественник-исследователь, картограф и первооткрыватель, член Королевского общества (1776) и капитан Королевских ВМС.', 'https://ru.wikipedia.org/wiki/%D0%9A%D1%83%D0%BA%2C_%D0%94%D0%B6%D0%B5%D0%B9%D0%BC%D1%81');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1778|Исследование Гавайских островов', 1778, 'Исследование Гавайских островов', 25, 'Гавайские острова', 21.3114, -157.7964, 'Джеймс Кук исследовал Гавайские острова во время своей третьей экспедиции. Джеймс Кук — британский военный моряк, путешественник-исследователь, картограф и первооткрыватель, член Королевского общества (1776) и капитан Королевских ВМС.', 'https://ru.wikipedia.org/wiki/%D0%9A%D1%83%D0%BA%2C_%D0%94%D0%B6%D0%B5%D0%B9%D0%BC%D1%81');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1785|Экспедиция Лаперуза', 1785, 'Экспедиция Лаперуза', 26, 'Тихий океан', 35.6762, 139.6503, 'Экспедиция Лаперуза внесла вклад в исследование Тихого океана и побережий Азии. Граф Жан-Франсуа́ де Гало́ де Лаперу́з — французский мореплаватель.', 'https://ru.wikipedia.org/wiki/%D0%9B%D0%B0%D0%BF%D0%B5%D1%80%D1%83%D0%B7%2C_%D0%96%D0%B0%D0%BD-%D0%A4%D1%80%D0%B0%D0%BD%D1%81%D1%83%D0%B0_%D0%B4%D0%B5');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1799|Исследование Южной Америки', 1799, 'Исследование Южной Америки', 27, 'Венесуэла', 7.6667, -65.2167, 'Александр Гумбольдт исследовал природу и географию Южной Америки, внёс большой вклад в развитие научной географии. Фридрих Вильгельм Генрих Алекса́ндр фон Гу́мбольдт — немецкий географ, натуралист и путешественник, один из основателей географии как самостоятельной науки; младший брат учёного Вильгельма фон Гумбольдта.', 'https://ru.wikipedia.org/wiki/%D0%93%D1%83%D0%BC%D0%B1%D0%BE%D0%BB%D1%8C%D0%B4%D1%82%2C_%D0%90%D0%BB%D0%B5%D0%BA%D1%81%D0%B0%D0%BD%D0%B4%D1%80_%D1%84%D0%BE%D0%BD');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1803|Первое русское кругосветное плавание', 1803, 'Первое русское кругосветное плавание', 28, 'Тихий океан', 59.9311, 30.3609, 'Экспедиция Ивана Крузенштерна стала первым русским кругосветным плаванием. Ива́н Фёдорович Крузенште́рн, А́дам Ио́ганн фон Кру́зенштерн — русский мореплаватель, возглавлявший в 1803—1806 годах первое русское кругосветное плавание.', 'https://ru.wikipedia.org/wiki/%D0%9A%D1%80%D1%83%D0%B7%D0%B5%D0%BD%D1%88%D1%82%D0%B5%D1%80%D0%BD%2C_%D0%98%D0%B2%D0%B0%D0%BD_%D0%A4%D1%91%D0%B4%D0%BE%D1%80%D0%BE%D0%B2%D0%B8%D1%87');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1804|Экспедиция Льюиса и Кларка', 1804, 'Экспедиция Льюиса и Кларка', 29, 'Северная Америка', 45.5152, -122.6784, 'Экспедиция Льюиса и Кларка исследовала западные территории Северной Америки. Мериуэ́зер Лью́ис — американский первопроходец, офицер и государственный служащий.', 'https://ru.wikipedia.org/wiki/%D0%9B%D1%8C%D1%8E%D0%B8%D1%81%2C_%D0%9C%D0%B5%D1%80%D0%B8%D1%83%D1%8D%D0%B7%D0%B5%D1%80');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1819|Экспедиция Джона Франклина', 1819, 'Экспедиция Джона Франклина', 30, 'Канадская Арктика', 68, -100, 'Джон Франклин участвовал в исследованиях арктических районов Северной Америки. Джон Фра́нклин — английский мореплаватель, исследователь Арктики, контр-адмирал.', 'https://ru.wikipedia.org/wiki/%D0%A4%D1%80%D0%B0%D0%BD%D0%BA%D0%BB%D0%B8%D0%BD%2C_%D0%94%D0%B6%D0%BE%D0%BD');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1820|Открытие Антарктиды', 1820, 'Открытие Антарктиды', 31, 'Антарктида', -69, 2, 'Русская экспедиция под руководством Беллинсгаузена и Лазарева впервые обнаружила берега Антарктиды. Фадде́й Фадде́евич Беллинсга́узен, имя при рождении Фабиан Готтлиб Беньямин фон Беллинсгаузен — русский мореплаватель, адмирал (1843), один из первооткрывателей Антарктиды.', 'https://ru.wikipedia.org/wiki/%D0%91%D0%B5%D0%BB%D0%BB%D0%B8%D0%BD%D1%81%D0%B3%D0%B0%D1%83%D0%B7%D0%B5%D0%BD%2C_%D0%A4%D0%B0%D0%B4%D0%B4%D0%B5%D0%B9_%D0%A4%D0%B0%D0%B4%D0%B4%D0%B5%D0%B5%D0%B2%D0%B8%D1%87');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1829|Исследование Австралии', 1829, 'Исследование Австралии', 32, 'Австралия', -34.9285, 138.6007, 'Чарльз Стерт исследовал внутренние районы Австралии и речные системы континента. Чарлз Нэпир Стерт — английский путешественник и колониальный деятель, исследователь Австралии.', 'https://ru.wikipedia.org/wiki/%D0%A1%D1%82%D0%B5%D1%80%D1%82%2C_%D0%A7%D0%B0%D1%80%D0%BB%D0%B7');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1841|Открытие моря Росса', 1841, 'Открытие моря Росса', 33, 'Антарктика', -75, 175, 'Джеймс Кларк Росс исследовал Антарктику и открыл море, названное его именем. Джеймс Кларк Росс — британский военный моряк, исследователь полярных районов, член Королевского географического общества с 1848 года.', 'https://ru.wikipedia.org/wiki/%D0%A0%D0%BE%D1%81%D1%81%2C_%D0%94%D0%B6%D0%B5%D0%B9%D0%BC%D1%81_%D0%9A%D0%BB%D0%B0%D1%80%D0%BA');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1849|Исследование Центральной Африки', 1849, 'Исследование Центральной Африки', 34, 'Африка', -17.9243, 25.8572, 'Давид Ливингстон исследовал районы Центральной и Южной Африки. Дави́д Ли́вингстон — шотландский миссионер, конгрегационалист, исследователь Африки.', 'https://ru.wikipedia.org/wiki/%D0%9B%D0%B8%D0%B2%D0%B8%D0%BD%D0%B3%D1%81%D1%82%D0%BE%D0%BD%2C_%D0%94%D0%B0%D0%B2%D0%B8%D0%B4');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1855|Открытие водопада Виктория для европейской науки', 1855, 'Открытие водопада Виктория для европейской науки', 34, 'Водопад Виктория', -17.9244, 25.8567, 'Ливингстон описал водопад Виктория, один из крупнейших водопадов мира. Дави́д Ли́вингстон — шотландский миссионер, конгрегационалист, исследователь Африки.', 'https://ru.wikipedia.org/wiki/%D0%9B%D0%B8%D0%B2%D0%B8%D0%BD%D0%B3%D1%81%D1%82%D0%BE%D0%BD%2C_%D0%94%D0%B0%D0%B2%D0%B8%D0%B4');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1858|Открытие озера Виктория для европейской науки', 1858, 'Открытие озера Виктория для европейской науки', 35, 'Озеро Виктория', -1, 33, 'Джон Хеннинг Спик исследовал район озера Виктория, связанный с поисками истоков Нила. Джон Хеннинг Спик — офицер британской индийской армии, исследователь Африки, в 1858 году обнаруживший озеро Виктория, а вместе с тем и исток Белого Нила.', 'https://ru.wikipedia.org/wiki/%D0%A1%D0%BF%D0%B8%D0%BA%2C_%D0%94%D0%B6%D0%BE%D0%BD_%D0%A5%D0%B5%D0%BD%D0%BD%D0%B8%D0%BD%D0%B3');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1860|Экспедиция Бёрка и Уиллса', 1860, 'Экспедиция Бёрка и Уиллса', 36, 'Австралия', -25, 135, 'Экспедиция Бёрка и Уиллса стала одной из известных попыток пересечь Австралию с юга на север. Роберт Бёркс — американский кинооператор.', 'https://ru.wikipedia.org/wiki/%D0%91%D1%91%D1%80%D0%BA%D1%81%2C_%D0%A0%D0%BE%D0%B1%D0%B5%D1%80%D1%82');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1871|Поиски Ливингстона', 1871, 'Поиски Ливингстона', 37, 'Озеро Танганьика', -5.5, 29.5, 'Генри Стэнли совершил экспедицию в Центральную Африку и встретил Давида Ливингстона. Ге́нри Мо́ртон Стэ́нли — британский журналист, путешественник, исследователь Африки.', 'https://ru.wikipedia.org/wiki/%D0%A1%D1%82%D1%8D%D0%BD%D0%BB%D0%B8%2C_%D0%93%D0%B5%D0%BD%D1%80%D0%B8_%D0%9C%D0%BE%D1%80%D1%82%D0%BE%D0%BD');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1874|Исследование реки Конго', 1874, 'Исследование реки Конго', 37, 'Река Конго', -6.0792, 12.45, 'Генри Стэнли исследовал бассейн реки Конго, расширив знания о Центральной Африке. Ге́нри Мо́ртон Стэ́нли — британский журналист, путешественник, исследователь Африки.', 'https://ru.wikipedia.org/wiki/%D0%A1%D1%82%D1%8D%D0%BD%D0%BB%D0%B8%2C_%D0%93%D0%B5%D0%BD%D1%80%D0%B8_%D0%9C%D0%BE%D1%80%D1%82%D0%BE%D0%BD');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1878|Открытие Северо-Восточного прохода', 1878, 'Открытие Северо-Восточного прохода', 38, 'Арктика', 75, 90, 'Норденшёльд первым прошёл Северо-Восточным проходом вдоль северных берегов Евразии. Барон Нильс Адольф Эрик Но́рденшельд (Ну́рденшёльд) — шведский геолог и географ, исследователь Арктики, мореплаватель, историк-картограф.', 'https://ru.wikipedia.org/wiki/%D0%9D%D0%BE%D1%80%D0%B4%D0%B5%D0%BD%D1%88%D0%B5%D0%BB%D1%8C%D0%B4%2C_%D0%90%D0%B4%D0%BE%D0%BB%D1%8C%D1%84_%D0%AD%D1%80%D0%B8%D0%BA');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1888|Пересечение Гренландии', 1888, 'Пересечение Гренландии', 39, 'Гренландия', 72, -40, 'Фритьоф Нансен первым пересёк ледниковый покров Гренландии. Фри́тьоф Ве́дель-Я́рлсберг На́нсен — норвежский полярный исследователь, учёный — доктор зоологии, основатель новой науки — физической океанографии, политический и общественный деятель, гуманист, филантроп, лауреат Нобелевской премии мира за 1922 год, удостоен наград многих стран.', 'https://ru.wikipedia.org/wiki/%D0%9D%D0%B0%D0%BD%D1%81%D0%B5%D0%BD%2C_%D0%A4%D1%80%D0%B8%D1%82%D1%8C%D0%BE%D1%84');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1893|Арктическая экспедиция на «Фраме»', 1893, 'Арктическая экспедиция на «Фраме»', 39, 'Арктический океан', 84, 30, 'Экспедиция Нансена на судне «Фрам» стала важным этапом в изучении Арктики. Фри́тьоф Ве́дель-Я́рлсберг На́нсен — норвежский полярный исследователь, учёный — доктор зоологии, основатель новой науки — физической океанографии, политический и общественный деятель, гуманист, филантроп, лауреат Нобелевской премии мира за 1922 год, удостоен наград многих стран.', 'https://ru.wikipedia.org/wiki/%D0%9D%D0%B0%D0%BD%D1%81%D0%B5%D0%BD%2C_%D0%A4%D1%80%D0%B8%D1%82%D1%8C%D0%BE%D1%84');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1897|Исследование Антарктики', 1897, 'Исследование Антарктики', 40, 'Антарктика', -64, -62, 'Экспедиция Адриена де Жерлаша стала одной из первых научных экспедиций, зимовавших в Антарктике. Адрие́н Викто́р Жозе́ф, барон де Жерла́ш де Гомери́.', 'https://ru.wikipedia.org/wiki/%D0%96%D0%B5%D1%80%D0%BB%D0%B0%D1%88%2C_%D0%90%D0%B4%D1%80%D0%B8%D0%B5%D0%BD_%D0%B4%D0%B5');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1909|Достижение Северного полюса', 1909, 'Достижение Северного полюса', 41, 'Северный полюс', 85, 0, 'Экспедиция Роберта Пири заявила о достижении Северного полюса. Ро́берт Э́двин Пи́ри — американский исследователь Арктики, путешественник.', 'https://ru.wikipedia.org/wiki/%D0%9F%D0%B8%D1%80%D0%B8%2C_%D0%A0%D0%BE%D0%B1%D0%B5%D1%80%D1%82');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1911|Достижение Южного полюса', 1911, 'Достижение Южного полюса', 42, 'Южный полюс', -85, 0, 'Руаль Амундсен первым достиг Южного полюса, завершив один из важнейших этапов полярных исследований. Ру́аль Э́нгельбрегт Гра́внинг А́мундсен — норвежский полярный путешественник-исследователь и рекордсмен, «Наполеон полярных стран» по выражению Роланда Хантфорда.', 'https://ru.wikipedia.org/wiki/%D0%90%D0%BC%D1%83%D0%BD%D0%B4%D1%81%D0%B5%D0%BD%2C_%D0%A0%D1%83%D0%B0%D0%BB%D1%8C');
INSERT INTO discoveries (id, year, title, explorer_id, location, lat, lng, description, source) VALUES ('1912|Экспедиция Роберта Скотта к Южному полюсу', 1912, 'Экспедиция Роберта Скотта к Южному полюсу', 43, 'Южный полюс', -85, 0, 'Экспедиция Роберта Скотта достигла Южного полюса вскоре после Амундсена и стала одной из самых известных полярных экспедиций.', 'https://ru.wikipedia.org/wiki/%D0%A1%D0%BA%D0%BE%D1%82%D1%82%2C_%D0%A0%D0%BE%D0%B1%D0%B5%D1%80%D1%82');
